import React, { useEffect, useState } from "react";
import WeatherOverlay from "./WeatherOverlay";
import Forecast from "./Forecast";
import Hourly from "./Hourly";
import BottomBar from "./BottomBar";
import SearchSection from "./SearchSection";

const API_BASE = process.env.REACT_APP_API_BASE || "http://127.0.0.1:8000";

// Safely extract nested keys
const get = (obj, path, fallback = "") =>
  path.split(".").reduce((o, k) => (o && o[k] != null ? o[k] : null), obj) ?? fallback;

// Normalize payload to a shape our components can handle
function normalizePayload(root) {
  if (!root || typeof root !== "object") return {};

  // current
  const current = root.current || {};
  const now = {
    dt: current.dt ?? Math.floor(Date.now() / 1000),
    temp: current.temp ?? null,
    weather: Array.isArray(current.weather) ? current.weather[0]?.description : current.weather || "",
    icon: Array.isArray(current.weather) ? current.weather[0]?.icon : current.icon || "",
  };

  // hourly — prefer direct OpenWeather pass-through
  let hourly = [];
  if (Array.isArray(root.hourly) && root.hourly.length) {
    hourly = root.hourly.map((h, i) => ({
      dt: h.dt ?? (Math.floor(Date.now() / 1000) + (i + 1) * 3600),
      temp: h.temp ?? h.main?.temp ?? null,
      pop: h.pop,
      precipitation:
        (h.precipitation != null ? h.precipitation : undefined) ??
        (h.rain && (h.rain["1h"] ?? h.rain["3h"])) ??
        (h.snow && (h.snow["1h"] ?? h.snow["3h"])) ??
        0,
      weather: h.weather ?? h.description ?? "",
      ...h,
    }));
  }

  // daily (short range)
  const daily = Array.isArray(root.daily)
    ? root.daily.map((d) => ({
        dt: d.dt,
        min: d.temp?.min ?? d.min,
        max: d.temp?.max ?? d.max,
        pop: d.pop,
        weather: Array.isArray(d.weather) ? d.weather[0]?.description : d.weather || "",
      }))
    : [];

  // extended forecast placeholder (if you add a 16-day endpoint later)
  const daily16 = root.daily16 || [];

  return {
    timezone: root.timezone || "local",
    current: now,
    hourly,
    daily,
    daily16,
  };
}

export default function WeatherApp() {
  const [weather, setWeather] = useState({});
  const [unit, setUnit] = useState("metric");
  const [location, setLocation] = useState("Atlanta,US");
  const [view, setView] = useState("now"); // now | forecast | radar | community

  useEffect(() => {
    if (!location) return;
    fetch(`${API_BASE}/api/weather/current`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ location }),
    })
      .then((res) => res.json())
      .then((data) => {
        setWeather(normalizePayload(data));
      })
      .catch((err) => {
        console.error("Weather fetch error", err);
      });
  }, [location]);

  return (
    <div className="relative min-h-screen flex flex-col bg-black text-white">
      <WeatherOverlay condition={weather?.current?.weather || ""} />

      {/* Top search */}
      <div className="p-4">
        <SearchSection onSelect={(loc) => setLocation(loc)} />
      </div>

      <div className="flex-1 overflow-y-auto px-4 pb-20">
        {view === "now" && (
          <div className="space-y-6">
            <div className="rounded-2xl p-4 bg-black/40 backdrop-blur">
              <div className="text-4xl font-bold">
                {Math.round(weather?.current?.temp ?? 0)}°
              </div>
              <div className="opacity-80 capitalize">
                {weather?.current?.weather || "—"}
              </div>
            </div>
            <Hourly
              hourly={weather.hourly}
              unit={unit}
              timezone={weather.timezone || "local"}
            />
          </div>
        )}

        {view === "forecast" && (
          <Forecast
            hourly={weather.hourly}
            daily={weather.daily}
            daily16={weather.daily16}
            unit={unit}
          />
        )}

        {view === "radar" && <div>Radar goes here</div>}
        {view === "community" && <div>Community section here</div>}
      </div>

      <BottomBar active={view} onNav={setView} />
    </div>
  );
}
